var maxAlternatingSum = function(nums) {
    const sq = nums.map(v => v * v).sort((a, b) => b - a);
    const plus = Math.ceil(sq.length / 2);
    let total = 0;
    for (let i = 0; i < sq.length; i++) total += i < plus ? sq[i] : -sq[i];
    return total;
};
